beforeSaveCustomScript:
// =====================================================
// VERSIONE: 1.1.1
// DATA: 09-05-2026 11:25
// FIX: Formula commerciale definitiva stabile
// =====================================================
//
// OBIETTIVO
// -----------------------------------------------------
// Questa formula gestisce:
//
// 1) Calcoli IVA
// 2) Sconto commerciale
// 3) Minus / Plus statistico
// 4) Provvigioni
//
// IMPORTANTE
// -----------------------------------------------------
// Il naming NON è gestito qui.
//
// Il naming è gestito nel hook:
//
// custom/Espo/Custom/Hooks/Opportunity/GlobalLogic.php
//
// IMPORTANTE
// -----------------------------------------------------
// amount = Importo Offerta IVA Inclusa
//
// =====================================================



// =====================================================
// PREZZO LISTINO IVA ESCLUSA
// =====================================================

ifThen(

    prezzoListinoIVAInclusa,

    prezzoListinoIvaEsclusa = number\format(

        prezzoListinoIVAInclusa
        /
        (
            1 + (iVAListino / 100)
        ),

        2
    )
);



// =====================================================
// PREZZO CODICE IVA ESCLUSA
// =====================================================

ifThen(

    prezzoCodiceIvaInclusa,

    prezzoCodiceIvaEsclusa = number\format(

        prezzoCodiceIvaInclusa
        /
        (
            1 + (iVAListino / 100)
        ),

        2
    )
);



// =====================================================
// IMPORTO OFFERTA IVA ESCLUSA
// =====================================================

ifThen(

    amount,

    importoOffertaIvaEsclusa = number\format(

        amount
        /
        (
            1 + (iVA / 100)
        ),

        2
    )
);



// =====================================================
// % SCONTO COMMERCIALE
// FIX POSITIVO
// =====================================================

ifThen(

    prezzoCodiceIvaInclusa,

    suPrezzoPromo = number\format(

        (
            (
                amount
                -
                prezzoCodiceIvaInclusa
            )
            /
            prezzoCodiceIvaInclusa
        ) * 100,

        2
    )
);



// =====================================================
// MINUS / PLUS
// VALORE STATISTICO IN EURO
// =====================================================

ifThen(

    prezzoCodiceIvaEsclusa,

    minusPlus = number\format(

        importoOffertaIvaEsclusa
        -
        prezzoCodiceIvaEsclusa,

        2
    )
);



// =====================================================
// % PLUS / MINUS
// VALORE STATISTICO PERCENTUALE
// =====================================================

ifThen(

    prezzoCodiceIvaEsclusa,

    plusMinus = number\format(

        (
            (
                importoOffertaIvaEsclusa
                /
                prezzoCodiceIvaEsclusa
            )
            -
            1
        ) * 100,

        2
    )
);



// =====================================================
// PROVVIGIONE TOTALE
// =====================================================

ifThen(

    provvigione,

    provvigioneTotale = number\format(

        provvigione,

        2
    )
);



// =====================================================
// IMPORTO PROVVIGIONE
// =====================================================

ifThen(

    provvigioneTotale,

    importoProvvigione = number\format(

        (
            importoOffertaIvaEsclusa
            *
            provvigioneTotale
        )
        / 100,

        2
    )
);
